import React, { useEffect, useState, useRef } from "react";
import axios from "axios";
import "./PriceList.css";

const API_URL = "http://localhost:7000/api/prices";
const CATEGORY_URL = "http://localhost:7000/api/categories";

export default function PriceList() {
  const [items, setItems] = useState([]);
  const [categories, setCategories] = useState([]);
  const [form, setForm] = useState({
    name: "",
    category: "",
    description: "",
    basePrice: "",
    difference: "",
    validTill: "",
    file: null,
  });
  const [editId, setEditId] = useState(null);
  const [loading, setLoading] = useState(false);
  const [csvFile, setCsvFile] = useState(null);
  const [addingCategory, setAddingCategory] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState("");
  const csvInputRef = useRef();

  useEffect(() => {
    fetchItems();
    fetchCategories();
  }, []);

  const fetchItems = async () => {
    setLoading(true);
    try {
      const res = await axios.get(API_URL);
      if (res.data.success) setItems(res.data.data);
    } catch (err) {
      console.error("Error fetching items:", err);
    } finally {
      setLoading(false);
    }
  };

  const fetchCategories = async () => {
    try {
      const res = await axios.get(CATEGORY_URL);
      if (res.data.success) setCategories(res.data.categories);
    } catch (err) {
      console.error("Error fetching categories:", err);
    }
  };

  const handleChange = (e) => {
    const { name, value, files } = e.target;
    if (files) setForm({ ...form, file: files[0] });
    else setForm({ ...form, [name]: value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      // validation
      if (!form.name || !form.category || !form.basePrice) {
        alert("Name, category and base price are required");
        setLoading(false);
        return;
      }

      const formData = new FormData();
      formData.append("name", form.name);
      formData.append("category", form.category);
      formData.append("description", form.description || "");
      formData.append("basePrice", form.basePrice);
      formData.append("difference", form.difference || 0);
      if (form.validTill) formData.append("validTill", form.validTill);
      if (form.file) formData.append("file", form.file);

      if (editId) await axios.put(`${API_URL}/${editId}`, formData);
      else await axios.post(API_URL, formData);

      setForm({
        name: "",
        category: "",
        description: "",
        basePrice: "",
        difference: "",
        validTill: "",
        file: null,
      });
      setEditId(null);
      fetchItems();
    } catch (err) {
      console.error("Error saving price:", err);
      alert("Error saving price, check console");
    } finally {
      setLoading(false);
    }
  };

  const handleEdit = (item) => {
    setForm({
      name: item.name,
      category: item.category?._id || "",
      description: item.description || "",
      basePrice: item.basePrice,
      difference: item.difference,
      validTill: item.validTill ? item.validTill.split("T")[0] : "",
      file: null,
    });
    setEditId(item._id);
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Are you sure you want to delete this item?")) return;
    setLoading(true);
    try {
      await axios.delete(`${API_URL}/${id}`);
      fetchItems();
    } catch (err) {
      console.error("Error deleting item:", err);
    } finally {
      setLoading(false);
    }
  };

  const handleCancel = () => {
    setForm({
      name: "",
      category: "",
      description: "",
      basePrice: "",
      difference: "",
      validTill: "",
      file: null,
    });
    setEditId(null);
  };

  // CSV import
  const handleCsvSelect = (e) => {
    setCsvFile(e.target.files[0]);
  };

  const handleImportCsv = async () => {
    if (!csvFile) return alert("Choose CSV file first");
    const fd = new FormData();
    fd.append("file", csvFile);
    setLoading(true);
    try {
      const res = await axios.post(`${API_URL}/import`, fd, {
        headers: { "Content-Type": "multipart/form-data" },
      });
      if (res.data.success) {
        alert(`Imported ${res.data.inserted || 0} items`);
        fetchItems();
        setCsvFile(null);
        if (csvInputRef.current) csvInputRef.current.value = null;
      } else {
        alert("Import completed with issues.");
      }
    } catch (err) {
      console.error("Import error:", err);
      alert("Import failed. Check console.");
    } finally {
      setLoading(false);
    }
  };

  // CSV export
  const handleExportCsv = async () => {
    try {
      setLoading(true);
      const res = await axios.get(`${API_URL}/export`, { responseType: "blob" });
      const blob = new Blob([res.data], { type: "text/csv;charset=utf-8;" });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = `prices_export_${Date.now()}.csv`;
      document.body.appendChild(a);
      a.click();
      a.remove();
      window.URL.revokeObjectURL(url);
    } catch (err) {
      console.error("Export error:", err);
      alert("Export failed. Check console.");
    } finally {
      setLoading(false);
    }
  };

  // Inline add category
  const handleAddCategory = async () => {
    if (!newCategoryName.trim()) return alert("Enter category name");
    try {
      const res = await axios.post(CATEGORY_URL, { name: newCategoryName.trim() });
      if (res.data.success) {
        setNewCategoryName("");
        setAddingCategory(false);
        fetchCategories();
        alert("Category added");
      } else {
        alert(res.data.message || "Could not add category");
      }
    } catch (err) {
      console.error("Add category error:", err);
      alert("Failed to add category");
    }
  };

  return (
    <div className="price-container">
      <div className="price-header">
        <h1>💰 Price Management</h1>
        <p>Manage product prices — add, edit, import CSV, export CSV</p>
      </div>

      <div className="price-form-card">
        <h2>{editId ? "✏️ Edit Price" : " Add New Price"}</h2>
        <form onSubmit={handleSubmit}>
          <div className="form-grid">
            <div className="form-group">
              <label>Product Name *</label>
              <input name="name" value={form.name} onChange={handleChange} placeholder="Enter product name" required />
            </div>

            <div className="form-group">
              <label>Category *</label>
              <div style={{ display: "flex", gap: 8 }}>
                <select name="category" value={form.category} onChange={handleChange} required>
                  <option value="">Select Category</option>
                  {categories.map((cat) => <option key={cat._id} value={cat._id}>{cat.name}</option>)}
                </select>
                <button type="button" className="btn small" onClick={() => setAddingCategory(!addingCategory)}>
                  {addingCategory ? "Close" : "Add"}
                </button>
              </div>
            </div>

            {addingCategory && (
              <div className="form-group full-width">
                <label>New Category Name</label>
                <div style={{ display: "flex", gap: 8 }}>
                  <input value={newCategoryName} onChange={(e) => setNewCategoryName(e.target.value)} placeholder="Category name" />
                  <button type="button" className="btn primary" onClick={handleAddCategory}>Create</button>
                </div>
              </div>
            )}

            <div className="form-group">
              <label>Base Price (₹) *</label>
              <input type="number" name="basePrice" value={form.basePrice} onChange={handleChange} min="0" step="0.01" required />
            </div>

            <div className="form-group">
              <label>Difference (₹)</label>
              <input type="number" name="difference" value={form.difference} onChange={handleChange} step="0.01" />
            </div>

            <div className="form-group">
              <label>Valid Till</label>
              <input type="date" name="validTill" value={form.validTill} onChange={handleChange} />
            </div>

            <div className="form-group">
              <label>Product Image</label>
              <input type="file" name="file" onChange={handleChange} accept="image/*" />
            </div>
          </div>

          <div className="form-group full-width">
            <label>Description</label>
            <textarea name="description" value={form.description} onChange={handleChange} rows="3" placeholder="Enter product description..." />
          </div>

          <div className="form-actions">
            <button type="submit" disabled={loading} className="btn primary">{loading ? "Processing..." : editId ? "Update Price" : "Add Price"}</button>
            {editId && <button type="button" onClick={handleCancel} className="btn cancel">Cancel</button>}
          </div>
        </form>
      </div>

      <div className="csv-controls">
        <div>
          <input type="file" accept=".csv,text/csv" ref={csvInputRef} onChange={handleCsvSelect} />
          <button onClick={handleImportCsv} className="btn small">Import CSV</button>
        </div>
        <div>
          <button onClick={handleExportCsv} className="btn">Export CSV</button>
        </div>
      </div>

      <div className="price-table-card">
        <div className="table-header">
          <h2>📋 Price List</h2>
          <span>Total: {items.length} items</span>
        </div>

        {loading ? <div className="loader">Loading...</div> : (items.length === 0 ? <p className="empty">No items found.</p> :
          <table>
            <thead>
              <tr>
                <th>Image</th>
                <th>Name</th>
                <th>Category</th>
                <th>Base Price</th>
                <th>Difference</th>
                <th>Final Price</th>
                <th>Valid Till</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {items.map((item) => (
                <tr key={item._id}>
                  <td>
                    {item.image ? <img src={item.image} alt={item.name} /> : <span className="no-img">No Image</span>}
                  </td>
                  <td>{item.name}</td>
                  <td>{item.category?.name || "N/A"}</td>
                  <td>₹{parseFloat(item.basePrice).toFixed(2)}</td>
                  <td>{item.difference ? `${item.difference > 0 ? "+" : ""}₹${parseFloat(item.difference).toFixed(2)}` : "-"}</td>
                  <td>₹{parseFloat(item.basePrice + (item.difference || 0)).toFixed(2)}</td>
                  <td>{item.validTill ? new Date(item.validTill).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" }) : "-"}</td>
                  <td className="actions">
                    <button className="btn edit" onClick={() => handleEdit(item)}>Edit</button>
                    <button className="btn delete" onClick={() => handleDelete(item._id)}>Delete</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}
